+package args
+
+import "testing"
+
+// TestLongFlagValueBeforePositional checks that a long flag attaches its
+// following token as a value before positionals begin.
+func TestLongFlagValueBeforePositional(t *testing.T) {
+	p, err := Parse([]string{"--window", "1h", "file.log"})
+	if err != nil {
+		t.Fatal(err)
+	}
+	if got := p.Str("window", ""); got != "1h" {
+		t.Fatalf("window = %q, want %q", got, "1h")
+	}
+	if len(p.Positional) != 1 || p.Positional[0] != "file.log" {
+		t.Fatalf("positional = %v, want [file.log]", p.Positional)
+	}
+}

