+package args
+
+import "testing"
+
+// TestLongFlagAttachesValueBeforePositionals checks the single core case
+// for the boundary fix: a long flag immediately followed by its value
+// consumes that value, and the remaining token lands as a positional.
+func TestLongFlagAttachesValueBeforePositionals(t *testing.T) {
+	p, err := Parse([]string{"--window", "1h", "file.log"})
+	if err != nil {
+		t.Fatalf("unexpected error: %v", err)
+	}
+	if got := p.Str("window", ""); got != "1h" {
+		t.Fatalf("window = %q, want %q", got, "1h")
+	}
+	if len(p.Positional) != 1 || p.Positional[0] != "file.log" {
+		t.Fatalf("positional = %v, want [file.log]", p.Positional)
+	}
+}
+
+// TestEqualsFormStillWorks guards the inline --flag=value form.
+func TestEqualsFormStillWorks(t *testing.T) {
+	p, _ := Parse([]string{"--root=/data", "x"})
+	if p.Str("root", "") != "/data" || len(p.Positional) != 1 {
+		t.Fatalf("got %+v", p)
+	}
+}

